// Enhanced fetch wrapper
const originalFetch = global.fetch;

global.fetch = async (url, options = {}) => {
  const timestamp = Date.now();
  
  Logger.logNetworkRequest(
    url,
    options.method || 'GET',
    options.body,
    timestamp
  );
  
  try {
    const response = await originalFetch(url, options);
    
    const responseText = await response.text();
    const parsedResponse = JSON.parse(responseText);
    
    Logger.logNetworkResponse(
      url,
      response.status,
      parsedResponse,
      timestamp
    );
    
    return new Response(responseText, {
      status: response.status,
      statusText: response.statusText,
      headers: response.headers
    });
  } catch (error) {
    console.error('Fetch error:', error);
    throw error;
  }
};

// Enhanced AsyncStorage wrapper
const originalAsyncStorage = AsyncStorage;

AsyncStorage.getItem = async (key) => {
  const timestamp = Date.now();
  const value = await originalAsyncStorage.getItem(key);
  
  Logger.logAsyncStorageOperation('get', key, value, timestamp);
  
  return value;
};

AsyncStorage.setItem = async (key, value) => {
  const timestamp = Date.now();
  
  Logger.logAsyncStorageOperation('set', key, value, timestamp);
  
  return await originalAsyncStorage.setItem(key, value);
};

AsyncStorage.removeItem = async (key) => {
  const timestamp = Date.now();
  
  Logger.logAsyncStorageOperation('remove', key, null, timestamp);
  
  return await originalAsyncStorage.removeItem(key);
};

